$failures=[];
foreach($checks as $check){
	try{
		$response=dataphyre_mcp_self_test_request(PHP_BINARY, $server, $root, $check['message']);
		if(isset($response['error']) && ($check['expect_error'] ?? false)!==true){
			throw new RuntimeException((string)($response['error']['message'] ?? 'Unknown MCP error.'));
		}
		$check['assert']($response);
		echo '[OK] '.$check['name'].PHP_EOL;
	}catch(Throwable $exception){
		$failures[]='[FAIL] '.$check['name'].': '.$exception->getMessage();
		echo end($failures).PHP_EOL;
	}
}

if($failures!==[]){
	fwrite(STDERR, "\nDataphyre MCP self-test failed with ".count($failures)." issue(s).\n");
	exit(1);
}

echo "Dataphyre MCP self-test passed.\n";
exit(0);

function dataphyre_mcp_self_test_write_route_manifest(string $path): void {
	$directory=dirname($path);
	if(!is_dir($directory) && !mkdir($directory, 0777, true) && !is_dir($directory)){
		throw new RuntimeException('Unable to create self-test cache directory.');
	}
	$payload=<<<'PHP'
<?php

return [
	'version'=>1,
	'metadata'=>['source'=>'mcp self-test'],
	'routes'=>[
		[
			'name'=>'orders.show',
			'methods'=>['GET'],
			'path'=>'/orders/{order_id}',
			'path_regex'=>'#^/orders/(?P<order_id>[0-9]+)$#',
			'defaults'=>[],
			'metadata'=>['module'=>'mcp_self_test'],
			'handler'=>['type'=>'controller', 'class'=>'Dataphyre\\Mcp\\SelfTestController', 'method'=>'show'],
			'middleware'=>[],
		],
	],
];
PHP;
	file_put_contents($path, $payload, LOCK_EX);
}

