function dataphyre_mcp_self_test_request(string $php, string $server, string $cwd, array $message): array {
	$body=json_encode($message, JSON_UNESCAPED_SLASHES);
	if(!is_string($body)){
		throw new RuntimeException('Unable to encode MCP request.');
	}
	$frame='Content-Length: '.strlen($body)."\r\n\r\n".$body;
	$descriptor=[
		0=>['pipe', 'r'],
		1=>['pipe', 'w'],
		2=>['pipe', 'w'],
	];
	$process=proc_open([$php, $server], $descriptor, $pipes, $cwd);
	if(!is_resource($process)){
		throw new RuntimeException('Unable to start MCP server.');
	}
	fwrite($pipes[0], $frame);
	fclose($pipes[0]);
	$stdout=stream_get_contents($pipes[1]);
	$stderr=stream_get_contents($pipes[2]);
	fclose($pipes[1]);
	fclose($pipes[2]);
	$exit=proc_close($process);
	if($exit!==0){
		throw new RuntimeException('MCP server exited '.$exit.($stderr!=='' ? ': '.$stderr : '.'));
	}
	return dataphyre_mcp_self_test_decode_frame((string)$stdout);
}

function dataphyre_mcp_self_test_replay_app_builder_continuation(array $arguments): array {
