	if(!is_string($root)){
		throw new RuntimeException('Unable to resolve workspace root for app-builder continuation replay.');
	}
	$server=$root.'/common/dataphyre/runtime/modules/mcp/kernel/dataphyre_mcp.php';
	return dataphyre_mcp_self_test_request(PHP_BINARY, $server, $root, [
		'jsonrpc'=>'2.0',
		'id'=>9164,
		'method'=>'tools/call',
		'params'=>[
			'name'=>'dataphyre_app_builder_plan_generate',
			'arguments'=>$arguments,
		],
	]);
}

function dataphyre_mcp_self_test_transport_hardening(string $php, string $server, string $cwd): void {
	$validLine=json_encode(['jsonrpc'=>'2.0', 'id'=>9001, 'method'=>'initialize', 'params'=>[]], JSON_UNESCAPED_SLASHES);
	if(!is_string($validLine)){
		throw new RuntimeException('Unable to encode line transport hardening request.');
	}
	$lineResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, "{bad-json}\n".$validLine."\n");
	if(
		count($lineResponses)<2
		|| (($lineResponses[0]['error']['code'] ?? null)!==-32700)
		|| !str_contains((string)($lineResponses[0]['error']['message'] ?? ''), 'Parse error')
		|| (($lineResponses[1]['id'] ?? null)!==9001)
		|| (($lineResponses[1]['result']['serverInfo']['name'] ?? null)!=='dataphyre-mcp')
	){
		throw new RuntimeException('MCP line transport did not report malformed JSON and continue to the next request.');
	}
	$invalidShapeResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, "[]\n{}\n".$validLine."\n");
	if(
		count($invalidShapeResponses)<3
		|| (($invalidShapeResponses[0]['error']['code'] ?? null)!==-32600)
		|| (($invalidShapeResponses[1]['error']['code'] ?? null)!==-32600)
		|| !str_contains((string)($invalidShapeResponses[0]['error']['message'] ?? ''), 'JSON-RPC message must be an object')
		|| !str_contains((string)($invalidShapeResponses[1]['error']['message'] ?? ''), 'JSON-RPC message must be an object')
		|| (($invalidShapeResponses[2]['id'] ?? null)!==9001)
		|| (($invalidShapeResponses[2]['result']['serverInfo']['name'] ?? null)!=='dataphyre-mcp')
	){
		throw new RuntimeException('MCP line transport did not reject non-object or methodless JSON-RPC messages and continue.');
	}

	$validFrameBody=json_encode(['jsonrpc'=>'2.0', 'id'=>9002, 'method'=>'initialize', 'params'=>[]], JSON_UNESCAPED_SLASHES);
	if(!is_string($validFrameBody)){
		throw new RuntimeException('Unable to encode framed transport hardening request.');
	}
	$invalidBody='{bad}';
	$raw='Content-Length: '.strlen($invalidBody)."\r\n\r\n".$invalidBody.'Content-Length: '.strlen($validFrameBody)."\r\n\r\n".$validFrameBody;
	$frameResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, $raw);
	if(
		count($frameResponses)<2
		|| (($frameResponses[0]['error']['code'] ?? null)!==-32700)
		|| !str_contains((string)($frameResponses[0]['error']['message'] ?? ''), 'Parse error')
		|| (($frameResponses[1]['id'] ?? null)!==9002)
		|| (($frameResponses[1]['result']['serverInfo']['name'] ?? null)!=='dataphyre-mcp')
	){
		throw new RuntimeException('MCP framed transport did not report malformed JSON and continue to the next request.');
	}
	$invalidShapeFrame='[]';
	$methodlessFrame='{}';
	$invalidShapeFrameResponses=dataphyre_mcp_self_test_raw_exchange(
		$php,
		$server,
		$cwd,
		'Content-Length: '.strlen($invalidShapeFrame)."\r\n\r\n".$invalidShapeFrame
			.'Content-Length: '.strlen($methodlessFrame)."\r\n\r\n".$methodlessFrame
			.'Content-Length: '.strlen($validFrameBody)."\r\n\r\n".$validFrameBody
	);
	if(
		count($invalidShapeFrameResponses)<3
		|| (($invalidShapeFrameResponses[0]['error']['code'] ?? null)!==-32600)
		|| (($invalidShapeFrameResponses[1]['error']['code'] ?? null)!==-32600)
		|| !str_contains((string)($invalidShapeFrameResponses[0]['error']['message'] ?? ''), 'JSON-RPC message must be an object')
		|| !str_contains((string)($invalidShapeFrameResponses[1]['error']['message'] ?? ''), 'JSON-RPC message must be an object')
		|| (($invalidShapeFrameResponses[2]['id'] ?? null)!==9002)
		|| (($invalidShapeFrameResponses[2]['result']['serverInfo']['name'] ?? null)!=='dataphyre-mcp')
	){
		throw new RuntimeException('MCP framed transport did not reject non-object or methodless JSON-RPC messages and continue.');
	}

	$missingLengthResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, "Content-Type: application/json\r\n\r\n");
	if(
		count($missingLengthResponses)!==1
		|| (($missingLengthResponses[0]['error']['code'] ?? null)!==-32600)
		|| !str_contains((string)($missingLengthResponses[0]['error']['message'] ?? ''), 'Content-Length')
	){
		throw new RuntimeException('MCP framed transport did not report missing Content-Length as an invalid request.');
	}
	foreach(['0', '-10', 'abc', '5abc', '1.5'] as $invalidLength){
		$invalidLengthResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, "Content-Length: {$invalidLength}\r\n\r\n{}");
		if(
			count($invalidLengthResponses)<1
			|| (($invalidLengthResponses[0]['error']['code'] ?? null)!==-32600)
			|| !str_contains((string)($invalidLengthResponses[0]['error']['message'] ?? ''), 'Content-Length')
		){
			throw new RuntimeException("MCP framed transport did not reject invalid Content-Length value {$invalidLength}.");
		}
	}
	$oversizedLengthResponses=dataphyre_mcp_self_test_raw_exchange($php, $server, $cwd, "Content-Length: 4194305\r\n\r\n{}");
	if(
		count($oversizedLengthResponses)<1
		|| (($oversizedLengthResponses[0]['error']['code'] ?? null)!==-32600)
		|| !str_contains((string)($oversizedLengthResponses[0]['error']['message'] ?? ''), 'maximum frame size')
	){
		throw new RuntimeException('MCP framed transport did not reject oversized Content-Length before reading the body.');
	}
}

function dataphyre_mcp_self_test_path_boundary(string $php, string $server, string $root): void {
	$sibling=$root.'-mcp-boundary-test';
	$file=$sibling.'/escape.md';
	if(!is_dir($sibling) && !mkdir($sibling, 0777, true) && !is_dir($sibling)){
		throw new RuntimeException('Unable to create MCP boundary test sibling directory.');
	}
	try{
		file_put_contents($file, "# Outside\n");
		$response=dataphyre_mcp_self_test_request($php, $server, $root, [
			'jsonrpc'=>'2.0',
			'id'=>9003,
			'method'=>'tools/call',
			'params'=>[
				'name'=>'dataphyre_read_doc',
				'arguments'=>['path'=>$file],
			],
		]);
		if(
			(($response['id'] ?? null)!==9003)
			|| (($response['error']['code'] ?? null)===null)
			|| !str_contains((string)($response['error']['message'] ?? ''), 'Path escapes the Dataphyre workspace')
			|| !str_contains((string)($response['error']['message'] ?? ''), '<absolute-path>')
			|| str_contains((string)($response['error']['message'] ?? ''), str_replace('\\', '/', $sibling))
		){
			throw new RuntimeException('safe_repo_path allowed a sibling path that only shared the repo-root prefix.');
		}
		$relativeSibling='../'.basename($sibling).'/escape.md';
		$relativeResponse=dataphyre_mcp_self_test_request($php, $server, $root, [
			'jsonrpc'=>'2.0',
			'id'=>9006,
			'method'=>'tools/call',
			'params'=>[
				'name'=>'dataphyre_read_doc',
				'arguments'=>['path'=>$relativeSibling],
			],
		]);
		if(
			(($relativeResponse['id'] ?? null)!==9006)
			|| (($relativeResponse['error']['code'] ?? null)===null)
			|| !str_contains((string)($relativeResponse['error']['message'] ?? ''), 'Path escapes the Dataphyre workspace')
			|| str_contains((string)($relativeResponse['error']['message'] ?? ''), str_replace('\\', '/', $sibling))
		){
			throw new RuntimeException('safe_repo_path allowed a relative sibling traversal outside the repo root.');
		}
		$backslashResponse=dataphyre_mcp_self_test_request($php, $server, $root, [
			'jsonrpc'=>'2.0',
			'id'=>9005,
			'method'=>'tools/call',
			'params'=>[
				'name'=>'dataphyre_read_doc',
				'arguments'=>['path'=>str_replace('/', '\\', $file)],
			],
		]);
		if(
			(($backslashResponse['id'] ?? null)!==9005)
			|| (($backslashResponse['error']['code'] ?? null)===null)
			|| !str_contains((string)($backslashResponse['error']['message'] ?? ''), 'Path escapes the Dataphyre workspace')
			|| !str_contains((string)($backslashResponse['error']['message'] ?? ''), '<absolute-path>')
			|| str_contains((string)($backslashResponse['error']['message'] ?? ''), str_replace('\\', '/', $sibling))
		){
			throw new RuntimeException('safe_repo_path allowed a backslash-normalized sibling path that only shared the repo-root prefix.');
		}
		$missingLeafResponse=dataphyre_mcp_self_test_request($php, $server, $root, [
			'jsonrpc'=>'2.0',
			'id'=>9004,
			'method'=>'tools/call',
			'params'=>[
				'name'=>'dataphyre_read_doc',
				'arguments'=>['path'=>$sibling.'/missing.md'],
			],
		]);
		if(
			(($missingLeafResponse['id'] ?? null)!==9004)
			|| (($missingLeafResponse['error']['code'] ?? null)===null)
			|| !str_contains((string)($missingLeafResponse['error']['message'] ?? ''), 'Path escapes the Dataphyre workspace')
			|| !str_contains((string)($missingLeafResponse['error']['message'] ?? ''), '<absolute-path>')
			|| str_contains((string)($missingLeafResponse['error']['message'] ?? ''), str_replace('\\', '/', $sibling))
		){
			throw new RuntimeException('safe_repo_path allowed a missing sibling leaf after resolving its parent directory.');
		}
	}
	finally{
		@unlink($file);
		@rmdir($sibling);
	}
}

function dataphyre_mcp_self_test_raw_exchange(string $php, string $server, string $cwd, string $input): array {
	$descriptor=[
		0=>['pipe', 'r'],
		1=>['pipe', 'w'],
		2=>['pipe', 'w'],
	];
	$process=proc_open([$php, $server], $descriptor, $pipes, $cwd);
	if(!is_resource($process)){
		throw new RuntimeException('Unable to start MCP server.');
	}
	fwrite($pipes[0], $input);
	fclose($pipes[0]);
	$stdout=stream_get_contents($pipes[1]);
	$stderr=stream_get_contents($pipes[2]);
	fclose($pipes[1]);
	fclose($pipes[2]);
	$exit=proc_close($process);
	if($exit!==0){
		throw new RuntimeException('MCP server exited '.$exit.($stderr!=='' ? ': '.$stderr : '.'));
	}
	return dataphyre_mcp_self_test_decode_responses((string)$stdout);
}

function dataphyre_mcp_self_test_decode_frame(string $frame): array {
	$parts=explode("\r\n\r\n", $frame, 2);
	if(count($parts)!==2){
		throw new RuntimeException('MCP response frame is missing header separator.');
	}
	$headers=[];
	foreach(explode("\r\n", $parts[0]) as $line){
		[$name, $value]=array_pad(explode(':', $line, 2), 2, '');
		$headers[strtolower(trim($name))]=trim($value);
	}
	$length=(int)($headers['content-length'] ?? 0);
	$body=substr($parts[1], 0, $length);
	$response=json_decode($body, true);
	if(!is_array($response)){
		throw new RuntimeException('MCP response body is not valid JSON.');
	}
	return $response;
}

function dataphyre_mcp_self_test_decode_responses(string $stream): array {
	$responses=[];
	$offset=0;
	$length=strlen($stream);
	while($offset<$length){
		while($offset<$length && ($stream[$offset]==="\r" || $stream[$offset]==="\n")){
			$offset++;
		}
		if($offset>=$length){
			break;
		}
		if(substr($stream, $offset, 15)==='Content-Length:'){
			$separator=strpos($stream, "\r\n\r\n", $offset);
			if($separator===false){
				throw new RuntimeException('MCP response stream frame is missing header separator.');
			}
			$header=substr($stream, $offset, $separator-$offset);
			$headers=[];
			foreach(explode("\r\n", $header) as $line){
				[$name, $value]=array_pad(explode(':', $line, 2), 2, '');
				$headers[strtolower(trim($name))]=trim($value);
			}
			$bodyLength=(int)($headers['content-length'] ?? 0);
			$bodyStart=$separator+4;
			$body=substr($stream, $bodyStart, $bodyLength);
			$offset=$bodyStart+$bodyLength;
		}else{
			$lineEnd=strpos($stream, "\n", $offset);
			if($lineEnd===false){
				$lineEnd=$length;
			}
			$body=rtrim(substr($stream, $offset, $lineEnd-$offset), "\r");
			$offset=$lineEnd+1;
		}
		$response=json_decode($body, true);
		if(!is_array($response)){
			throw new RuntimeException('MCP response stream body is not valid JSON: '.$body);
		}
		$responses[]=$response;
	}
	return $responses;
}

function dataphyre_mcp_self_test_assert_no_ordinary_app_escalation_instructions(array $data, string $context): void {
	$violations=[];
	dataphyre_mcp_self_test_scan_ordinary_app_escalation_instructions($data, [], false, $violations);
	if($violations!==[]){
		throw new RuntimeException($context.' contains positive maintainer/release-proof instructions in ordinary app-builder guidance: '.json_encode(array_slice($violations, 0, 6), JSON_UNESCAPED_SLASHES));
	}
}

function dataphyre_mcp_self_test_compact_matches_have_discriminators(mixed $matches): bool {
	if(!is_array($matches) || $matches===[]){
		return false;
	}
	$discriminator_keys=['group', 'kind', 'description', 'module', 'path', 'fetch_tool', 'match_reasons', 'title'];
	foreach($matches as $match){
		if(!is_array($match) || trim((string)($match['name'] ?? ''))===''){
			return false;
		}
		$has_discriminator=false;
		foreach($discriminator_keys as $key){
			$value=$match[$key] ?? null;
			if(is_array($value) ? $value!==[] : trim((string)$value)!==''){
				$has_discriminator=true;
				break;
			}
		}
		if(!$has_discriminator){
			return false;
		}
	}
	return true;
}

function dataphyre_mcp_self_test_scan_ordinary_app_escalation_instructions(mixed $value, array $path, bool $instruction_scope, array &$violations): void {
	$key=(string)end($path);
	if(dataphyre_mcp_self_test_is_allowed_boundary_path($path)){
		return;
	}
	$next_instruction_scope=$instruction_scope || dataphyre_mcp_self_test_is_instruction_bearing_key($key);
	if(is_array($value)){
		foreach($value as $child_key=>$child_value){
			$child_path=$path;
			$child_path[]=(string)$child_key;
			dataphyre_mcp_self_test_scan_ordinary_app_escalation_instructions($child_value, $child_path, $next_instruction_scope, $violations);
		}
		return;
	}
	if(!$next_instruction_scope || !is_scalar($value)){
		return;
	}
	$text=(string)$value;
	if(!dataphyre_mcp_self_test_has_positive_ordinary_app_escalation_instruction($text)){
		return;
	}
	$violations[]=[
		'path'=>implode('.', $path),
		'text'=>substr($text, 0, 240),
	];
}

function dataphyre_mcp_self_test_is_allowed_boundary_path(array $path): bool {
	$allowed=[
		'not_required',
		'not_included',
		'not_default_for_ordinary_app_work',
		'not_required_for_ordinary_app_work',
		'not_ordinary_app_ceremony',
		'escalate_only_for',
		'escalate_only_when',
		'escalation_policy',
		'publication_validation',
		'publication_validation_tools',
		'publication_next_action',
		'application_agent_operating_contract',
		'ordinary_app_work',
		'tool_audience_boundaries',
		'payload_budget',
		'context_links',
		'optional_context',
		'omitted_inline_detail',
	];
	foreach($path as $part){
		$part=(string)$part;
		if(in_array($part, $allowed, true) || str_starts_with($part, 'not_')){
			return true;
		}
	}
	return false;
}

function dataphyre_mcp_self_test_is_instruction_bearing_key(string $key): bool {
	return in_array($key, [
		'action',
		'next_action',
		'run_after',
		'when',
		'purpose',
		'policy',
		'secondary_context',
		'post_write_handoff_template',
		'resume_cursor',
		'write_source',
		'then_read',
		'copy_safe_handoff',
		'done_when',
		'open_rule',
		'overflow_action',
	], true);
}

function dataphyre_mcp_self_test_has_positive_ordinary_app_escalation_instruction(string $text): bool {
	$normalized=strtolower($text);
	foreach(['not required', 'does not ', 'do not ', 'don\'t ', 'without ', 'exclude ', 'excluded ', 'unless ', 'only for ', 'not ordinary', 'not a release', 'not app behavior proof'] as $negation){
		if(str_contains($normalized, $negation)){
			return false;
		}
	}
	$positive_verbs='run|execute|call|invoke|use|require|requires|must|should';
	foreach([
		'/\b('.$positive_verbs.')\b[^.]{0,120}\bdataphyre_mcp_verify_all\b/',
		'/\b('.$positive_verbs.')\b[^.]{0,120}\b(Dataphyre project-wide release validation|maintainer\/source-checkout evidence)\b/',
		'/\b('.$positive_verbs.')\b[^.]{0,120}\b(dataphyre hot-path benchmark|hot-path benchmark|benchmark evidence)\b/',
		'/\b('.$positive_verbs.')\b[^.]{0,120}\b(mcp\/release-surface validation|release validation|publication validation)\b/',
	] as $pattern){
		if(preg_match($pattern, $normalized)===1){
			return true;
		}
	}
	return false;
}

function dataphyre_mcp_self_test_shared_mcp_app_coupling_guard(string $root): void {
	$paths=[];
	$mcpRoot=$root.'/common/dataphyre/runtime/modules/mcp';
	if(is_dir($mcpRoot)){
		$iterator=new RecursiveIteratorIterator(new RecursiveDirectoryIterator($mcpRoot, FilesystemIterator::SKIP_DOTS));
		foreach($iterator as $file){
			if($file instanceof SplFileInfo && $file->isFile() && in_array(strtolower($file->getExtension()), ['php', 'md', 'json'], true)){
				$paths[]=$file->getPathname();
			}
		}
	}
	foreach(['mcp_config.php', 'mcp_live_validate.php'] as $helper){
		$path=$root.'/common/dataphyre/dev/tools/public/'.$helper;
		if(is_file($path)){
			$paths[]=$path;
		}
	}
	$productNeedles=[
		'sho'.'piro',
		'Sho'.'piro',
		'applications/sho'.'piro',
		'applications\\sho'.'piro',
		'north'.'star',
		'North'.'star',
		'vestra'.'-control',
		'vestra'.'_control',
		'applications/vestra'.'_control',
		'applications\\vestra'.'_control',
		'volume'.'trix',
		'Volume'.'trix',
		'applications/volume'.'trix',
		'applications\\volume'.'trix',
		'exo'.'dus',
		'Exo'.'dus',
		'applications/exo'.'dus',
		'applications\\exo'.'dus',
		'applications/north'.'star',
		'.local\\sho'.'piro',
		'Bureau\\ShopiCore',
		'OneDrive\\Bureau',
	];
	foreach(array_values(array_unique($paths)) as $path){
		$text=(string)file_get_contents($path);
		foreach($productNeedles as $needle){
			if(str_contains($text, $needle)){
				throw new RuntimeException('Shared MCP file contains product-specific fixture text '.$needle.': '.str_replace('\\', '/', substr($path, strlen($root)+1)));
			}
		}
	}
}

function dataphyre_mcp_self_test_prepare_application_catalog_fixtures(string $root): void {
	$fixtures=[
		'mcp_catalog_primary'=>[
			'backend/dataphyre/config/mvc.php'=>"<?php\nreturn [\n\t'controllers'=>['namespace'=>'McpCatalogPrimary\\\\Controllers'],\n\t'models'=>['namespace'=>'McpCatalogPrimary\\\\Models'],\n];\n",
			'backend/dataphyre/config/sql.php'=>"<?php\nreturn [];\n",
			'backend/dataphyre/config/panel.php'=>"<?php\nreturn [];\n",
		],
		'mcp_catalog_fallback'=>[
			'backend/dataphyre/config/sql.php'=>"<?php\nreturn [];\n",
		],
		'mcp_catalog_legacy'=>[
			'dataphyre/config/sql.php'=>"<?php\nreturn [];\n",
		],
	];
	$fixture_roots=[];
	foreach($fixtures as $app=>$files){
		$app_root=$root.'/applications/'.$app;
		$fixture_roots[]=$app_root;
		foreach($files as $relative=>$contents){
			$path=$app_root.'/'.$relative;
			$directory=dirname($path);
			if(!is_dir($directory) && !mkdir($directory, 0777, true) && !is_dir($directory)){
				throw new RuntimeException('Unable to create MCP app catalog fixture directory: '.$directory);
			}
			file_put_contents($path, $contents);
		}
	}
	register_shutdown_function(static function() use ($fixture_roots): void {
		foreach($fixture_roots as $fixture_root){
			dataphyre_mcp_self_test_remove_fixture_tree($fixture_root);
		}
	});
}

function dataphyre_mcp_self_test_remove_fixture_tree(string $path): void {
	if(!is_dir($path)){
		return;
	}
	$iterator=new RecursiveIteratorIterator(
		new RecursiveDirectoryIterator($path, FilesystemIterator::SKIP_DOTS),
		RecursiveIteratorIterator::CHILD_FIRST
	);
	foreach($iterator as $file){
		if(!$file instanceof SplFileInfo){
			continue;
		}
		if($file->isDir()){
			@rmdir($file->getPathname());
		}else{
			@unlink($file->getPathname());
		}
	}
	@rmdir($path);
}

function dataphyre_mcp_self_test_between(string $source, string $start, string $end): string {
	$startPosition=strpos($source, $start);
	if($startPosition===false){
		throw new RuntimeException("Unable to find source marker: {$start}");
	}
	$endPosition=strpos($source, $end, $startPosition);
	if($endPosition===false){
		throw new RuntimeException("Unable to find source marker: {$end}");
	}
	return substr($source, $startPosition, $endPosition-$startPosition);
}

function dataphyre_mcp_self_test_workspace_root(string $tool_dir): ?string {
	$real_tool_dir=realpath($tool_dir);
	if(!is_string($real_tool_dir)){
		return null;
	}
	$candidates=[
		realpath($real_tool_dir.'/../../../../..'),
		getcwd() ?: null,
	];
	foreach($candidates as $candidate){
		if(!is_string($candidate) || $candidate===''){
			continue;
		}
		$root=rtrim(str_replace('\\', '/', $candidate), '/');
		if(is_file($root.'/common/dataphyre/runtime/modules/mcp/kernel/dataphyre_mcp.php')){
			return $root;
		}
	}
	$source_candidates=[
		realpath($real_tool_dir.'/../../..'),
		getcwd() ?: null,
	];
	foreach($source_candidates as $candidate){
		if(!is_string($candidate) || $candidate===''){
			continue;
		}
		$source_root=rtrim(str_replace('\\', '/', $candidate), '/');
		if(is_file($source_root.'/runtime/modules/mcp/kernel/dataphyre_mcp.php')){
			return dataphyre_mcp_self_test_source_embedded_workspace($source_root);
		}
	}
	return null;
}

function dataphyre_mcp_self_test_source_embedded_workspace(string $source_root): ?string {
	$workspace=rtrim(str_replace('\\', '/', sys_get_temp_dir()), '/').'/dataphyre-mcp-self-test-'.substr(sha1($source_root), 0, 12).'-'.getmypid();
	$common=$workspace.'/common';
	$link=$common.'/dataphyre';
	if(!is_dir($common) && !@mkdir($common, 0777, true) && !is_dir($common)){
		return null;
	}
	if(is_file($link.'/runtime/modules/mcp/kernel/dataphyre_mcp.php')){
		register_shutdown_function('dataphyre_mcp_self_test_cleanup_embedded_workspace', $workspace, $link);
		return $workspace;
	}
	if(@symlink($source_root, $link) || dataphyre_mcp_self_test_windows_junction($source_root, $link)){
		if(is_file($link.'/runtime/modules/mcp/kernel/dataphyre_mcp.php')){
			register_shutdown_function('dataphyre_mcp_self_test_cleanup_embedded_workspace', $workspace, $link);
			return $workspace;
		}
	}
	dataphyre_mcp_self_test_cleanup_embedded_workspace($workspace, $link);
	return null;
}

function dataphyre_mcp_self_test_windows_junction(string $source_root, string $link): bool {
	if(PHP_OS_FAMILY!=='Windows'){
		return false;
	}
	$command='cmd /c mklink /J '.escapeshellarg(str_replace('/', '\\', $link)).' '.escapeshellarg(str_replace('/', '\\', $source_root));
	@exec($command, $output, $exit_code);
	return $exit_code===0;
}

function dataphyre_mcp_self_test_cleanup_embedded_workspace(string $workspace, string $link): void {
	if(is_link($link)){
		@unlink($link);
	}
	elseif(is_dir($link)){
		@rmdir($link);
	}
	@rmdir(dirname($link));
	@rmdir($workspace);
}

